import React, { createContext, useContext, useState, useCallback } from 'react';

const CLAVE_CARRITO = 'productoCarrito';

function leerCarritoStorage() {
  try {
    const data = localStorage.getItem(CLAVE_CARRITO);
    if (!data) return [];
    const parsed = JSON.parse(data);
    return Array.isArray(parsed) ? parsed : [parsed];
  } catch { return []; }
}

const CarritoContexto = createContext(null);

export function CarritoProvider({ children }) {
  const [carrito, setCarrito] = useState(leerCarritoStorage);

  const guardar = useCallback((items) => {
    localStorage.setItem(CLAVE_CARRITO, JSON.stringify(items));
    setCarrito(items);
  }, []);

  const agregarItem = useCallback((item) => {
    const actual = leerCarritoStorage();
    const nuevo = [...actual, item];
    guardar(nuevo);
  }, [guardar]);

  const eliminarItem = useCallback((indice) => {
    const actual = leerCarritoStorage();
    actual.splice(indice, 1);
    guardar([...actual]);
  }, [guardar]);

  const vaciarCarrito = useCallback(() => {
    guardar([]);
  }, [guardar]);

  const sincronizar = useCallback(() => {
    setCarrito(leerCarritoStorage());
  }, []);

  return (
    <CarritoContexto.Provider value={{ carrito, agregarItem, eliminarItem, vaciarCarrito, sincronizar }}>
      {children}
    </CarritoContexto.Provider>
  );
}

export function useCarrito() {
  return useContext(CarritoContexto);
}
